const body = items[0].json.body || items[0].json;

const client = {
  clientName: body.clientName || body.company_name || 'New Client',
  clientEmail: (body.clientEmail || body.email || '').toLowerCase().trim(),
  contactName: body.contactName || body.contact_name || '',
  contactFirstName: body.contactFirstName || (body.contactName || '').split(' ')[0] || 'there',
  packageType: body.packageType || body.package || 'standard',
  projectName: body.projectName || body.project || `${body.clientName || 'Client'} - Onboarding`,
  startDate: body.startDate || new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  accountManagerEmail: body.accountManagerEmail || body.am_email || 'team@yourcompany.com',
  onboardingId: `ONB-${Date.now().toString(36).toUpperCase()}`,
  createdAt: new Date().toISOString()
};

// Calculate key dates
const start = new Date(client.startDate);
client.welcomeCallDate = new Date(start.getTime() - 3 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
client.kickoffDate = client.startDate;
client.firstCheckInDate = new Date(start.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
client.thirtyDayReviewDate = new Date(start.getTime() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

// Determine onboarding steps based on package
if (client.packageType === 'premium' || client.packageType === 'enterprise') {
  client.includesStrategySession = true;
  client.includesDedicatedSlackChannel = true;
  client.includesCustomTraining = true;
} else {
  client.includesStrategySession = false;
  client.includesDedicatedSlackChannel = false;
  client.includesCustomTraining = false;
}

return [{ json: client }];

