parameters.functionCode:
const client = items[0].json;

// Define the standard onboarding subtasks
const subtasks = [
  {
    title: `Send welcome email`,
    dueOffset: 0,
    status: 'completed',
    assignee: 'system'
  },
  {
    title: `Receive completed intake form from ${client.contactFirstName}`,
    dueOffset: 2,
    status: 'pending',
    assignee: client.accountManagerEmail
  },
  {
    title: `Schedule and conduct welcome call`,
    dueOffset: 3,
    status: 'pending',
    assignee: client.accountManagerEmail
  },
  {
    title: `Set up client in internal systems (billing, project tracking, docs)`,
    dueOffset: 3,
    status: 'pending',
    assignee: client.accountManagerEmail
  },
  {
    title: `Create shared folder/workspace for ${client.clientName}`,
    dueOffset: 3,
    status: 'pending',
    assignee: client.accountManagerEmail
  },
  {
    title: `Conduct project kickoff meeting`,
    dueOffset: 7,
    status: 'pending',
    assignee: client.accountManagerEmail
  },
  {
    title: `Deliver initial project plan / statement of work`,
    dueOffset: 10,
    status: 'pending',
    assignee: client.accountManagerEmail
  },
  {
    title: `First week check-in call`,
    dueOffset: 14,
    status: 'pending',
    assignee: client.accountManagerEmail
  },
  {
    title: `30-day review and feedback collection`,
    dueOffset: 30,
    status: 'pending',
    assignee: client.accountManagerEmail
  }
];

// Add premium-only tasks
if (client.includesStrategySession) {
  subtasks.splice(6, 0, {
    title: `Schedule strategy deep-dive session`,
    dueOffset: 5,
    status: 'pending',
    assignee: client.accountManagerEmail
  });
}

if (client.includesDedicatedSlackChannel) {
  subtasks.splice(3, 0, {
    title: `Create dedicated Slack channel #client-${client.clientName.toLowerCase().replace(/\s+/g, '-')}`,
    dueOffset: 1,
    status: 'pending',
    assignee: client.accountManagerEmail
  });
}

if (client.includesCustomTraining) {
  subtasks.push({
    title: `Schedule custom training session for ${client.contactFirstName}'s team`,
    dueOffset: 21,
    status: 'pending',
    assignee: client.accountManagerEmail
  });
}

// Calculate actual due dates
const startDate = new Date(client.startDate);
const tasksWithDates = subtasks.map((task, index) => {
  const dueDate = new Date(startDate.getTime() + task.dueOffset * 24 * 60 * 60 * 1000);
  return {
    ...task,
    dueDate: dueDate.toISOString().split('T')[0],
    order: index + 1,
    clientName: client.clientName,
    onboardingId: client.onboardingId
  };
});

return tasksWithDates.map(task => ({ json: task }));

